class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n + 1))
    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]
    def union(self, x, y):
        rootX = self.find(x)
        rootY = self.find(y)
        if rootX != rootY:
            self.parent[rootY] = rootX

def main():
    n = int(input())
    uf = UnionFind(n)
    for _ in range(n):
        u, v = map(int, input().split())
        uf.union(u, v)
    m = int(input())
    for _ in range(m):
        u, v = map(int, input().split())
        if uf.find(u) == uf.find(v):
            print("YES")
        else:
            print("NO")
if __name__ == '__main__':
    main()

